  "inlineSchema": "// =============================================================\n// Prisma Schema — Realtime Interactive Polling App\n// Provider: MySQL (вимагає MySQL 8.0.16+ для Enum як CHECK constraints)\n//\n// Архітектурні рішення:\n// - Enum типи визначені нативно через Prisma enum (MySQL CHECK constraints)\n// - Result.optionIds зберігається як JSON для підтримки MULTIPLE_CHOICE\n//   без денормалізації таблиці\n// - Session.currentQuestion — для MANUAL режиму зберігає стан в БД\n//   (джерело правди), Redis кешує для швидкого доступу з WebSocket\n// =============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n}\n\n// ─── Enum: Тип питання ────────────────────────────────────────\nenum QuestionType {\n  SINGLE_CHOICE // Один правильний варіант\n  MULTIPLE_CHOICE // Кілька правильних варіантів\n}\n\n// ─── Enum: Режим прогресії сесії ─────────────────────────────\n// MANUAL     — організатор вручну перемикає питання для всіх\n// SELF_PACED — кожен учасник просувається індивідуально після відповіді\nenum ProgressionMode {\n  MANUAL\n  SELF_PACED\n}\n\n// ─── Enum: Стан сесії ─────────────────────────────────────────\nenum SessionStatus {\n  WAITING // Лобі — очікуємо учасників\n  ACTIVE // Сесія йде\n  FINISHED // Завершена\n}\n\n// ─── Model: User (Організатор) ───────────────────────────────\nmodel User {\n  id        Int      @id @default(autoincrement())\n  email     String   @unique @db.VarChar(255)\n  password  String   @db.VarChar(255) // bcrypt hash\n  name      String   @db.VarChar(100)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  polls    Poll[]\n  sessions Session[]\n\n  @@map(\"users\")\n}\n\n// ─── Model: Poll (Опитування) ────────────────────────────────\nmodel Poll {\n  id          Int      @id @default(autoincrement())\n  title       String   @db.VarChar(255)\n  description String?  @db.Text\n  organizerId Int\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  organizer User       @relation(fields: [organizerId], references: [id], onDelete: Cascade)\n  questions Question[]\n  sessions  Session[]\n\n  @@index([organizerId])\n  @@map(\"polls\")\n}\n\n// ─── Model: Question (Питання) ───────────────────────────────\nmodel Question {\n  id        Int          @id @default(autoincrement())\n  text      String       @db.Text\n  timeLimit Int // Секунди (0 = без ліміту)\n  type      QuestionType\n  order     Int // Порядковий номер у опитуванні (для сортування)\n  pollId    Int\n  createdAt DateTime     @default(now())\n\n  poll    Poll     @relation(fields: [pollId], references: [id], onDelete: Cascade)\n  options Option[]\n  results Result[]\n\n  @@index([pollId, order]) // Складений індекс для швидкої пагінації по порядку\n  @@map(\"questions\")\n}\n\n// ─── Model: Option (Варіант відповіді) ───────────────────────\nmodel Option {\n  id         Int      @id @default(autoincrement())\n  text       String   @db.VarChar(500)\n  isCorrect  Boolean  @default(false) // Ніколи не передається клієнту напряму!\n  questionId Int\n  createdAt  DateTime @default(now())\n\n  question Question @relation(fields: [questionId], references: [id], onDelete: Cascade)\n\n  @@index([questionId])\n  @@map(\"options\")\n}\n\n// ─── Model: Session (Ігрова сесія) ───────────────────────────\nmodel Session {\n  id              Int             @id @default(autoincrement())\n  pin             String          @unique @db.VarChar(6) // 6-значний код підключення\n  status          SessionStatus   @default(WAITING)\n  progressionMode ProgressionMode // Режим прогресії — ключове поле архітектури\n  currentQuestion Int             @default(0) // Для MANUAL: поточний індекс питання\n  pollId          Int\n  organizerId     Int\n  createdAt       DateTime        @default(now())\n  updatedAt       DateTime        @updatedAt\n\n  poll      Poll     @relation(fields: [pollId], references: [id])\n  organizer User     @relation(fields: [organizerId], references: [id])\n  results   Result[]\n\n  @@index([pollId])\n  @@index([organizerId])\n  @@map(\"sessions\")\n}\n\n// ─── Model: Result (Результат відповіді) ─────────────────────\n// Архітектурне рішення: optionIds зберігається як JSON масив.\n// Це уникає окремої таблиці many-to-many (ResultOption) і дозволяє\n// ефективно зберігати як [1] для SINGLE_CHOICE, так і [1,3,5] для MULTIPLE_CHOICE.\n// Flush з Redis до MySQL виконується батчами при переході питань.\nmodel Result {\n  id            Int      @id @default(autoincrement())\n  sessionId     Int\n  questionId    Int\n  participantId String   @db.VarChar(36) // UUID v4 учасника (persistent через reconnects)\n  optionIds     Json // Array<number> — обраний(-і) варіант(-и)\n  score         Int      @default(0) // 0–100 балів за питання\n  answeredAt    DateTime @default(now())\n\n  session  Session  @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  question Question @relation(fields: [questionId], references: [id])\n\n  // Унікальна пара: один учасник — одна відповідь на питання в сесії\n  @@unique([sessionId, questionId, participantId])\n  @@index([sessionId, questionId])\n  @@map(\"results\")\n}\n"
